-- Dangerous commands blacklist (never allow these even if accidentally whitelisted)
local BLOCKED_COMMANDS = {
    ["flushdb"] = true,
    ["flushall"] = true,
    ["shutdown"] = true,
    ["config"] = true,
    ["debug"] = true,
