local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    ngx.exit(status)
end

local function send_error(status, message)
    send_json_response(status, {
        success = false,
        error = message
    })
end

local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown error")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Failed to authenticate with Redis: " .. (err or "unknown error")
        end
    end

    return red, nil
end

local function keepalive_redis(red)
    if red then
        local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
        if not ok then
            ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
        end
    end
end

local function parse_redis_result(result)
    if type(result) == "table" then
        -- Check for Redis null bulk reply
        local processed = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                processed[i] = cjson.null
            elseif type(v) == "table" then
                processed[i] = parse_redis_result(v)
            else
                processed[i] = v
            end
        end
        return processed
    elseif result == ngx.null then
        return cjson.null
    else
        return result
    end
end

local function validate_command(cmd)
    if not cmd or cmd == "" then
        return false, "Command is required"
    end

    local lower_cmd = string.lower(cmd)

    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function parse_args(args_param)
    if not args_param then
        return {}
    end

    if type(args_param) == "table" then
        return args_param
    end

    -- Try JSON parse first
    local ok, parsed = pcall(cjson.decode, args_param)
    if ok and type(parsed) == "table" then
        return parsed
    end

    -- Fall back to single argument
    return { args_param }
end

local function get_request_body_json()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body"
    end

    return data, nil
end

local function execute_command(red, cmd, args)
    local lower_cmd = string.lower(cmd)
    local func = red[lower_cmd]

    if not func then
        return nil, "Unknown Redis command: " .. cmd
    end

    local result, err
    if #args == 0 then
        result, err = func(red)
    else
        result, err = func(red, unpack(args))
    end

    if not result then
        return nil, "Redis command failed: " .. (err or "unknown error")
    end

    return parse_redis_result(result), nil
end

local function execute_eval(red, script, num_keys, keys, argv)
    num_keys = tonumber(num_keys) or 0
    keys = keys or {}
    argv = argv or {}

    -- Build the arguments for eval: script, numkeys, key1..keyN, arg1..argN
    local eval_args = { script, num_keys }
    for _, k in ipairs(keys) do
        table.insert(eval_args, k)
    end
    for _, a in ipairs(argv) do
        table.insert(eval_args, a)
    end

    local result, err = red:eval(unpack(eval_args))
    if not result then
        return nil, "Redis EVAL failed: " .. (err or "unknown error")
    end

    return parse_redis_result(result), nil
end

local function execute_pipeline(red, commands)
    if not commands or #commands == 0 then
        return nil, "No commands provided for pipeline"
    end

    red:init_pipeline()

    for i, cmd_entry in ipairs(commands) do
        local cmd = cmd_entry.command or cmd_entry.cmd
        if not cmd then
            return nil, "Command #" .. i .. " is missing the 'command' field"
        end

        local valid, verr = validate_command(cmd)
        if not valid then
            return nil, "Command #" .. i .. ": " .. verr
        end

        local args = parse_args(cmd_entry.args)
        local lower_cmd = string.lower(cmd)
        local func = red[lower_cmd]

        if not func then
            return nil, "Unknown Redis command at #" .. i .. ": " .. cmd
        end

        if #args == 0 then
            func(red)
        else
            func(red, unpack(args))
        end
    end

    local results, err = red:commit_pipeline()
    if not results then
        return nil, "Pipeline execution failed: " .. (err or "unknown error")
    end

    local processed = {}
    for i, result in ipairs(results) do
        if type(result) == "table" and result[1] == false then
            processed[i] = {
                success = false,
                error = result[2]
            }
        else
            processed[i] = {
                success = true,
                result = parse_redis_result(result)
            }
        end
    end

    return processed, nil
end

-- Main request handler
local function handle_request()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri

    -- Health check endpoint
    if uri == "/health" or uri == "/ping" then
        local red, err = connect_redis()
        if not red then
            send_error(503, err)
            return
        end

        local result, rerr = red:ping()
        keepalive_redis(red)

        if not result then
            send_error(503, "Redis ping failed: " .. (rerr or "unknown"))
            return
        end

        send_json_response(200, {
            success = true,
            result = "PONG",
            redis = REDIS_HOST .. ":" .. REDIS_PORT
        })
        return
    end

    -- Command info endpoint - list allowed commands
    if uri == "/commands" then
        local cmds = {}
        for cmd, _ in pairs(ALLOWED_COMMANDS) do
            table.insert(cmds, cmd)
        end
        table.sort(cmds)
        send_json_response(200, {
            success = true,
            allowed_commands = cmds,
            total = #cmds
        })
        return
    end

    -- Eval endpoint
    if uri == "/eval" then
        if method ~= "POST" then
            send_error(405, "Method not allowed. Use POST for /eval")
            return
        end

        local body, berr = get_request_body_json()
        if not body then
            send_error(400, berr)
            return
        end

        local script = body.script
        if not script or script == "" then
            send_error(400, "Lua script is required in 'script' field")
            return
        end

        local num_keys = tonumber(body.num_keys or body.numkeys) or 0
        local keys = body.keys or {}
        local argv = body.args or body.argv or {}

        if type(keys) ~= "table" then
            keys = { keys }
        end
        if type(argv) ~= "table" then
            argv = { argv }
        end

        local red, err = connect_redis()
        if not red then
            send_error(503, err)
            return
        end

        local result, rerr = execute_eval(red, script, num_keys, keys, argv)
        keepalive_redis(red)

        if not result and rerr then
            send_error(500, rerr)
            return
        end

        send_json_response(200, {
            success = true,
            result = result
        })
        return
    end

    -- Pipeline endpoint
    if uri == "/pipeline" then
        if method ~= "POST" then
            send_error(405, "Method not allowed. Use POST for /pipeline")
            return
        end

        local body, berr = get_request_body_json()
        if not body then
            send_error(400, berr)
            return
        end

        local commands = body.commands
        if not commands or type(commands) ~= "table" or #commands == 0 then
            send_error(400, "'commands' array is required")
            return
        end

        if #commands > 100 then
            send_error(400, "Maximum 100 commands allowed in a pipeline")
            return
        end

        local red, err = connect_redis()
        if not red then
            send_error(503, err)
            return
        end

        local results, rerr = execute_pipeline(red, commands)
        keepalive_redis(red)

        if not results then
            send_error(500, rerr)
            return
        end

        send_json_response(200, {
            success = true,
            results = results,
            count = #results
        })
        return
    end

    -- Main command execution endpoint
    if uri == "/command" or uri == "/cmd" or uri == "/" then
        local cmd, args

        if method == "GET" then
            local params = ngx.req.get_uri_args()
            cmd = params.command or params.cmd
            local raw_args = params.args

            if not cmd then
                send_error(400, "Missing 'command' or 'cmd' query parameter")
                return
            end

            args = parse_args(raw_args)

            -- Also support positional args like arg1, arg2, arg3...
            if #args == 0 then
                local i = 1
                while true do
                    local arg_val = params["arg" .. i]
                    if not arg_val then
                        break
                    end
                    table.insert(args, arg_val)
                    i = i + 1
                end
            end

            -- Support key/value shorthand for common operations
            if #args == 0 and params.key then
                table.insert(args, params.key)
                if params.value then
                    table.insert(args, params.value)
                end
                if params.field then
                    -- For hash operations, insert field before value
                    if params.value then
                        args = { params.key, params.field, params.value }
                    else
                        args = { params.key, params.field }
                    end
                end
            end

        elseif method == "POST" then
            local body, berr = get_request_body_json()
            if not body then
                send_error(400, berr)
                return
            end

            cmd = body.command or body.cmd
            if not cmd then
                send_error(400, "Missing 'command' or 'cmd' field in request body")
                return
            end

            args = parse_args(body.args)

            -- Support key/value in body as well
            if #args == 0 and body.key then
                table.insert(args, body.key)
                if body.field then
                    table.insert(args, body.field)
                end
                if body.value then
                    table.insert(args, body.value)
                end
            end
        else
            send_error(405, "Method not allowed. Use GET or POST")
            return
        end

        -- Validate command
        local valid, verr = validate_command(cmd)
        if not valid then
            send_error(403, verr)
            return
        end

        -- Connect to Redis
        local red, err = connect_redis()
        if not red then
            send_error(503, err)
            return
        end

        -- Execute command
        local result, rerr = execute_command(red, cmd, args)
        keepalive_redis(red)

        if not result and rerr then
            send_error(500, rerr)
            return
        end

        send_json_response(200, {
            success = true,
            command = string.upper(cmd),
            args = args,
            result = result
        })
        return
    end

    -- REST-style key access: /key/<keyname>
    local key_match = ngx.re.match(uri, "^/key/(.+)$")
    if key_match then
        local key = key_match[1]

        local red, err = connect_redis()
        if not red then
            send_error(503, err)
            return
        end

        if method == "GET" then
            -- Auto-detect type and retrieve accordingly
            local key_type, terr = red:type(key)
            if not key_type or key_type == ngx.null then
                keepalive_redis(red)
                send_error(404, "Key not found")
                return
            end

            local result, rerr

            if key_type == "string" then
                result, rerr = red:get(key)
            elseif key_type == "hash" then
                result, rerr = red:hgetall(key)
                if result and type(result) == "table" then
                    -- Convert flat array to hash table
                    local hash = {}
                    for i = 1, #result, 2 do
                        hash[result[i]] = result[i + 1]
                    end
                    result = hash
                end
            elseif key_type == "list" then
                result, rerr = red:lrange(key, 0, -1)
            elseif key_type == "set" then
                result, rerr = red:smembers(key)
            elseif key_type == "zset" then
                result, rerr = red:zrange(key, 0, -1, "WITHSCORES")
                if result and type(result) == "table" then
                    local zset = {}
                    for i = 1, #result, 2 do
                        table.insert(zset, { member = result[i], score = tonumber(result[i + 1]) })
                    end
                    result = zset
                end
            elseif key_type == "none" then
                keepalive_redis(red)
                send_error(404, "Key '" .. key .. "' does not exist")
                return
            else
                keepalive_redis(red)
                send_error(400, "Unsupported key type: " .. tostring(key_type))
                return
            end

            -- Get TTL
            local ttl = red:ttl(key)
            keepalive_redis(red)

            if not result or result == ngx.null then
                send_error(404, "Key '" .. key .. "' not found or empty")
                return
            end

            send_json_response(200, {
                success = true,
                key = key,
                type = key_type,
                ttl = (ttl and ttl ~= ngx.null) and ttl or -1,
                value = parse_redis_result(result)
            })
            return

        elseif method == "PUT" or method == "POST" then
            local body, berr = get_request_body_json()
            if not body then
                send_error(400, berr)
                return
            end

            local value = body.value
            local ttl = tonumber(body.ttl or body.expire)
            local data_type = body.type or "string"

            if value == nil then
                keepalive_redis(red)
                send_error(400, "'value' field is required")
                return
            end

            local result, rerr

            if data_type == "string" then
                local str_value = type(value) == "table" and cjson.encode(value) or tostring(value)
                if ttl and ttl > 0 then
                    result, rerr = red:setex(key, ttl, str_value)
                else
                    result, rerr = red:set(key, str_value)
                end
            elseif data_type == "hash" and type(value) == "table" then
                red:del(key)
                local flat = {}
                for k, v in pairs(value) do
                    table.insert(flat, k)
                    table.insert(flat, tostring(v))
                end
                if #flat > 0 then
                    result, rerr = red:hmset(key, unpack(flat))
                end
                if ttl and ttl > 0 then
                    red:expire(key, ttl)
                end
            elseif data_type == "list" and type(value) == "table" then
                red:del(key)
                for _, v in ipairs(value) do
                    result, rerr = red:rpush(key, tostring(v))
                end
                if ttl and ttl > 0 then
                    red:expire(key, ttl)
                end
            elseif data_type == "set" and type(value) == "table" then
                red:del(key)
                for _, v in ipairs(value) do
                    result, rerr = red:sadd(key, tostring(v))
                end
                if ttl and ttl > 0 then
                    red:expire(key, ttl)
                end
            else
                keepalive_redis(red)
                send_error(400, "Unsupported type or value format")
                return
            end

            keepalive_redis(red)

            if not result then
                send_error(500, "Failed to set key: " .. (rerr or "unknown error"))
                return
            end

            send_json_response(201, {
                success = true,
                key = key,
                type = data_type,
                message = "Key set successfully"
            })
            return

        elseif method == "DELETE" then
            local result, rerr = red:del(key)
            keepalive_redis(red)

            if not result then
                send_error(500, "Failed to delete key: " .. (rerr or "unknown error"))
                return
            end

            send_json_response(200, {
                success = true,
                key = key,
                deleted = result
            })
            return
        else
            send_error(405, "Method not allowed")
            return
        end
    end

    -- If no route matched
    send_json_response(404, {
        success = false,
        error = "Endpoint not found",
        available_endpoints = {
            "GET/POST /command - Execute a Redis command",
            "GET/POST /cmd - Alias for /command",
            "POST /eval - Execute Lua script via EVAL",
            "POST /pipeline - Execute multiple commands in pipeline",
            "GET/PUT/POST/DELETE /key/<keyname> - REST-style key operations",
            "GET /commands - List allowed commands",
            "GET /health - Health check"
        }
    })
end

-- Execute the handler
local ok, err = pcall(handle_request)
if not ok then
    ngx.log(ngx.ERR, "Request handler error: ", err)
    send_error(500, "Internal server error")
end